import{_ as n,j as i,o as t,v as e}from"./chunks/framework.dn0DPyqd.js";const h=JSON.parse('{"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","frontmatter":{"footer":true,"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","authors":["lethanh"],"date":"2024-10-09T00:00:00.000Z","outline":"deep","image":"/assets/KafkaProducer12.qYn0oVGH.png","draft":true},"headers":[{"level":2,"title":"Những sai lầm.","slug":"nhung-sai-lam","link":"#nhung-sai-lam","children":[{"level":3,"title":"The network is reliable","slug":"the-network-is-reliable","link":"#the-network-is-reliable","children":[]},{"level":3,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo The network is reliable.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable","children":[]},{"level":3,"title":"Latency is zero","slug":"latency-is-zero","link":"#latency-is-zero","children":[]}]}],"relativePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","filePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","lastUpdated":1728493987000}'),l={name:"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md"},a=[e('<ul><li>Fallacies of distributed computing là một tập hợp các khẳng định được tập hợp bởi <a href="https://en.wikipedia.org/wiki/L._Peter_Deutsch" target="_blank" rel="noreferrer">L. Peter Deutsch</a> và một số người tại <a href="https://en.wikipedia.org/wiki/Sun_Microsystems" target="_blank" rel="noreferrer">Sun Microsystems</a> mô tả về những giả định sai lầm của các lập tình viên đanng làm việc với ứng dụng phân tán.</li></ul><h2 id="nhung-sai-lam" tabindex="-1">Những sai lầm. <a class="header-anchor" href="#nhung-sai-lam" aria-label="Permalink to &quot;Những sai lầm.&quot;">​</a></h2><h3 id="the-network-is-reliable" tabindex="-1">The network is reliable <a class="header-anchor" href="#the-network-is-reliable" aria-label="Permalink to &quot;The network is reliable&quot;">​</a></h3><p><strong>The network is reliable</strong>: Dịch tiếng việt là <code>Mạng lưới đáng tin cậy</code>. Đây là 1 sai lầm nghiêm trọng nhưng cũng hay xảy ra nhất.</p><p>Rất nhiều lập trình viên tin rằng các kết nối mạng đến node hoặc hệ thống khác sẽ tốt và luôn không có vấn đề gì xảy ra. Tuy nhiên kết nối mạng rất sẽ bị lỗi bởi nhiều nguyên nhân như mất kết nối, không có quyền, lỗi phần cứng...etc..</p><p>Hệ thống cần có một cơ chế linh loạt bao gồm đầy đủ các tính năng dự phòng khi mất kết nối đến các hệ thống khác.</p><details class="details custom-block"><summary>Ví dụ: Hệ thống A không thể gọi đến hệ thống B</summary><ul><li>Hệ thống A có thể gọi đến các dịch vụ dự phòng ví dụ như thay vì chỉ sử dụng Cache redis chúng có có thể thêm sử dụng EVCache khi redis lỗi.</li><li>Hệ thống A cung cấp tính năng retry.</li></ul></details><h3 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>The network is reliable</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `The network is reliable`.&quot;">​</a></h3><p>Sẽ có rất nhiều cách để đảm bảo hệ thống của chúng ta là <code>network is reliable</code> khi chúng ta là phụ thuộc của các hệ thống khác, dưới đây là một số ví dụ.</p><ul><li>Cung cấp load balance để phân tải hệ thống, phòng ngừa hệ thống sập.</li><li>Auto scale để mở rộng quy mô tự động.</li><li>Cung cấp tính năng sử dụng Asynchronous messaging.</li><li>Sử dụng CDN và deploy hệ thống ở nhiều khu vực.</li><li>...</li></ul><h3 id="latency-is-zero" tabindex="-1">Latency is zero <a class="header-anchor" href="#latency-is-zero" aria-label="Permalink to &quot;Latency is zero&quot;">​</a></h3><p><strong>Latency is zero</strong> : Dịch tiếng việt là độ trễ là 0.</p><p>Tình huống được kiểm tra phổ biến bởi các lập trình viên là các hệ thống phụ thuộc không hoạt động. Tuy nhiên một trong những trường hợp hay xảy ra đó là các phụ thuộc hoạt động chậm.</p><p>Các hệ thống có thể bị đột ngột tăng lượng người sử dụng đột biến, mạng hệ thống chậm, mạng kết nối chậm... everything.., điều này sẽ tác động đến các hệ thống gửi phản hồi(Response) lại cho người dùng chậm hơn.</p><p>Hệ thống cần có các cơ chế để phòng ngừa tình trạng các hệ thống khác phản hồi chậm.</p><details class="details custom-block"><summary>Ví dụ: Hệ thống A gọi đến hệ thống B bị chậm lên tới 90s hoặc hơn.</summary><ul><li>A là hệ thống bất đồng bộ, các request từ client sẽ được đưa vào Queue xử lý dần dần.</li><li>A cài đặt thời gian timeout tối đa cho mỗi request gửi đến B.</li><li>Cấu hình Circuit breaker để ngắt kết nối tạm thời đến B khi B bị lỗi quá số lần cấu hình</li><li>Sử dụng Bulkhead pattern để ngăn chặn service B lỗi gây nên sập toàn hệ thống.</li><li>Một số response của B có thể được cache lại tại A. (Ví dụ tên sản phẩm có Id = 100)</li><li></li></ul></details>',16)];const c=n(l,[["render",function(n,e,h,l,c,g){return t(),i("div",null,a)}]]);export{h as __pageData,c as default};
